const data = $input.first().json.body;

if (!data.alumnos || !Array.isArray(data.alumnos) || data.alumnos.length === 0) {
  return [{ json: {
    status: 'error',
    mensaje: 'Campo obligatorio: alumnos (array de nombres). Ejemplo: ["Maria Garcia", "Carlos Lopez"]'
  } }];
}

const longitud = data.longitud || 12;
const mayusculas = 'ABCDEFGHJKLMNPQRSTUVWXYZ';
const minusculas = 'abcdefghjkmnpqrstuvwxyz';
const numeros = '23456789';
const simbolos = '!@#$%&*';
const todos = mayusculas + minusculas + numeros + simbolos;

function generarContrasena(len) {
  // Asegurar al menos un caracter de cada tipo
  let pass = '';
  pass += mayusculas.charAt(Math.floor(Math.random() * mayusculas.length));
  pass += minusculas.charAt(Math.floor(Math.random() * minusculas.length));
  pass += numeros.charAt(Math.floor(Math.random() * numeros.length));
  pass += simbolos.charAt(Math.floor(Math.random() * simbolos.length));
  for (let i = 4; i < len; i++) {
    pass += todos.charAt(Math.floor(Math.random() * todos.length));
  }
  // Mezclar los caracteres
  return pass.split('').sort(() => Math.random() - 0.5).join('');
}

function generarUsuario(nombre) {
  return nombre
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, '.')
    .replace(/[^a-z0-9.]/g, '');
}

const credenciales = data.alumnos.map(nombre => ({
  alumno: nombre,
  usuario: generarUsuario(nombre),
  contrasena: generarContrasena(longitud)
}));

return [{ json: {
  status: 'ok',
  total: credenciales.length,
  longitud_contrasena: longitud,
  credenciales,
  generado: new Date().toLocaleString('es-ES', { timeZone: 'Europe/Madrid' })
} }];
